import React, { useEffect, useState } from 'react';

import './CardCarrousel.css';


const URL = 'https://instagram-api-gamma.vercel.app/';

async function Fetch() {
    const resp = await fetch(URL);

    if (resp.status === 200) {
        const obj = await resp.json();
        return obj;
    }
}

